const mongoose = require('mongoose');

function queryBuilder(filter, projection, sort) {
    return function (callback) {
        const Model = this; // Assuming the context is a Mongoose model instance
        
        let query = Model.find();
        
        if (filter && typeof filter === 'object') {
            for (let key in filter) {
                if(filter[key] instanceof RegExp){
                    query = query.where(key).equals(new RegExp(filter[key], "i")); // Case insensitive regex search
                } else {
                    query = query.where(key).equals(filter[key]); 
                }
            }
        }
        
        if (projection && typeof projection === 'object') {
            for (let key in projection) {
                let value = projection[key];
                
                // Mongoose's select method accepts a string or an object. If it is a number, we assume it to be 1 (show field) or 0 (hide field).
                if(typeof value === 'number'){
                    value = value === 1 ? true : false;
                }
                
                query = query.select({[key]: value});
            }
        }
        
        if (sort && typeof sort === 'object') {
            for (let key in sort) {
                let value = sort[key];
                
                // Mongoose's sort method accepts a string or an object. If it is a number, we assume it to be 1 (ascending order) or -1 (descending order).
                if(typeof value === 'number'){
                    value = value === 1 ? 1 : -1;
                }
                
                query = query.sort({[key]: value});
            }
        }
        
        return query.exec(callback); // Execute the query and pass the callback function to handle results
    };
}